def _extract_last_metrics_dict(result: Dict[str, Any]) -> Dict[str, Any]:
    # 1) res
    if isinstance(result.get("res"), dict):
        return result["res"]
    out = result.get("output")
    if isinstance(out, dict) and isinstance(out.get("res"), dict):
        return out["res"]

    # 2) extracted_output：可能是 dict，也可能是 list
    ex = result.get("extracted_output")
    exd = _pick_dict_from_any(ex)  # dict or None
    if exd is None:
        return {}

    rs = exd.get("results")
    # results 可能是 list，也可能直接是 dict（极少数），也可能是别的
    if isinstance(rs, list) and rs:
        last = _pick_dict_from_any(rs[-1])  # rs[-1] 通常就是 dict
        if isinstance(last, dict):
            return last
        # 再兜底：从整个 results list 里找最后一个 dict
        last2 = _pick_dict_from_any(rs)
        return last2 or {}
    if isinstance(rs, dict):
        return rs

    return {}
